import json

def validate_json_response(response: str, required_keys: list[str]) -> tuple[bool, str]:
    try:
        data = json.loads(response)
    except json.JSONDecodeError as e:
        return False, f'Invalid JSON: {e}'
    missing = [k for k in required_keys if k not in data]
    if missing:
        return False, f'Missing keys: {missing}'
    return True, 'Valid'

# Usage:
valid, msg = validate_json_response('{"sentiment": "positive", "confidence": 0.9}', ['sentiment', 'confidence'])
print(valid, msg)  # True, 'Valid'
